function createExecutorContext({
  session,
  userContent,
  requestContext
}) {
  return {
    userId: session.userId,
    sessionId: session.id,
    agentName: session.appName,
    readonlyState: session.state,
    events: session.events,
    userContent,
    requestContext
  };
}
export {
  createExecutorContext
};
